export const CITY_OPTIONS = Object.values(TRAVEL_ROUTES).map((city) => ({
  value: city.id,
  label: `${city.name} · ${city.caseName}`,
}));

export function getRoute(
  cityId: string,
  theme: string,
  duration: DurationKey
): RoutePlan | null {
  const city = TRAVEL_ROUTES[cityId];
  if (!city) return null;
  const plans = city.themes[theme];
  if (!plans) return null;
  const index = duration === "1day" ? 0 : duration === "2days" ? 1 : 2;
  return plans[index] ?? null;
}

export function getFirstAvailableRoute(cityId: string): RoutePlan | null {
  const city = TRAVEL_ROUTES[cityId];
  if (!city) return null;
  for (const plans of Object.values(city.themes)) {
    if (plans.length > 0) return plans[0];
  }
  return null;
}
